import{_ as o,o as t,c as a,ag as s}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Voice Notes","description":"","frontmatter":{},"headers":[],"relativePath":"coach-notes/voice-notes.md","filePath":"coach-notes/voice-notes.md"}'),i={name:"coach-notes/voice-notes.md"};function r(n,e,c,h,l,p){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="voice-notes" tabindex="-1">Voice Notes <a class="header-anchor" href="#voice-notes" aria-label="Permalink to &quot;Voice Notes&quot;">​</a></h1><p>Voice notes let you dictate coaching observations without typing. The spoken text runs through the same AI processing pipeline as typed notes.</p><h2 id="how-to-use-voice-notes" tabindex="-1">How to Use Voice Notes <a class="header-anchor" href="#how-to-use-voice-notes" aria-label="Permalink to &quot;How to Use Voice Notes&quot;">​</a></h2><ol><li>Tap <strong>Voice Note</strong> from the dashboard, Notes hub, or player profile</li><li><strong>On mobile:</strong> Tap the microphone icon on your keyboard and speak</li><li><strong>On desktop:</strong> Tap the microphone button in the voice note interface and speak</li><li>Tap <strong>Process Notes with AI</strong> when done</li></ol><p>The transcribed text appears in the text field before processing — you can edit it before submitting.</p><h2 id="what-to-say" tabindex="-1">What to Say <a class="header-anchor" href="#what-to-say" aria-label="Permalink to &quot;What to Say&quot;">​</a></h2><p>Speak naturally about what you observed. The AI handles free-form speech — you do not need to follow a structure.</p><p><strong>Example:</strong> &quot;Today at practice I noticed Glaros still dropping his elbow on the fastball — same thing from last week. Hupp had a great day at the plate, made solid contact on everything we threw him. Dean needs work on his backhand — booted two easy ones at short.&quot;</p><p>That single voice note extracts three separate player observations, identifies Glaros&#39;s issue as recurring, and generates appropriate suggestions for each.</p><h2 id="after-game-voice-notes" tabindex="-1">After Game Voice Notes <a class="header-anchor" href="#after-game-voice-notes" aria-label="Permalink to &quot;After Game Voice Notes&quot;">​</a></h2><p>The most efficient use of voice notes is immediately after a game or practice while observations are fresh — walk to your car and dictate for two minutes. This captures far more detail than trying to reconstruct the game later.</p><h2 id="voice-note-vs-voice-logging" tabindex="-1">Voice Note vs Voice Logging <a class="header-anchor" href="#voice-note-vs-voice-logging" aria-label="Permalink to &quot;Voice Note vs Voice Logging&quot;">​</a></h2><p><strong>Voice logging</strong> (in the Game Hub or Practice Hub) logs plays to specific stat categories in real time during a game.</p><p><strong>Voice notes</strong> (in the Notes hub) capture coaching observations for later AI processing. They do not log stats — they capture qualitative observations about player development.</p>',14)])])}const u=o(i,[["render",r]]);export{g as __pageData,u as default};
